<?php
namespace Tests\Feature\Hr;
use App\Models\LegalEntity; use App\Models\User; use App\Modules\Hr\Core\Services\TenantContext; use App\Modules\Hr\Engagement\Actions\CreateSurveyAction; use App\Modules\Hr\Engagement\Actions\GiveRecognitionAction; use App\Modules\Hr\Engagement\Actions\SubmitSurveyResponseAction; use App\Modules\Hr\Personnel\Models\HrEmployee; use Illuminate\Support\Facades\DB; use Tests\TestCase;
class EngagementWorkflowTest extends TestCase { use RefreshHrDatabase; private LegalEntity $tenant; private int $role; private User $admin; private array $employees=[]; protected function setUp():void{parent::setUp();(new \Database\Seeders\Hr\HrPermissionSeeder)->run();$this->role=(int)DB::table('roles')->where('slug','hr_admin')->value('id');$this->admin=User::factory()->create(['role_id'=>$this->role]);$this->actingAs($this->admin);$this->tenant=LegalEntity::create(['user_id'=>$this->admin->id,'name'=>'Bağlılık','tax_number'=>'6161616161','is_active'=>true]);app(TenantContext::class)->set($this->tenant);for($i=1;$i<=3;$i++){$user=$i===1?$this->admin:User::factory()->create(['role_id'=>$this->role]);$this->employees[]=HrEmployee::withoutGlobalScope('tenant')->create(['legal_entity_id'=>$this->tenant->id,'user_id'=>$user->id,'employee_number'=>'ENG'.$i,'national_id_encrypted'=>'enc','national_id_hash'=>'engagement-'.$i,'national_id_last_four'=>'000'.$i,'first_name'=>'Çalışan'.$i,'last_name'=>'Test','status'=>'active']);}}
public function test_anonymous_survey_does_not_store_employee_and_prevents_duplicate():void{$survey=$this->activeSurvey();$employee=$this->employees[0];$response=app(SubmitSurveyResponseAction::class)->execute($survey,$employee,['enps'=>9,'energy'=>4]);$this->assertNull($response->employee_id);$this->assertNotEmpty($response->respondent_hash);$this->assertDatabaseHas('activity_logs',['action'=>'engagement_survey_response_submitted','user_id'=>null,'ip_address'=>null]);$this->expectException(\Symfony\Component\HttpKernel\Exception\HttpException::class);app(SubmitSurveyResponseAction::class)->execute($survey,$employee,['enps'=>8,'energy'=>3]);}
public function test_three_responses_produce_expected_enps_without_identity():void{$survey=$this->activeSurvey();$scores=[10,9,4];foreach($this->employees as $i=>$employee){$this->actingAs($employee->user);app(SubmitSurveyResponseAction::class)->execute($survey,$employee,['enps'=>$scores[$i],'energy'=>4]);}$responses=$survey->responses()->get();$enps=round(($responses->where('enps_score','>=',9)->count()/$responses->count()*100)-($responses->where('enps_score','<=',6)->count()/$responses->count()*100));$this->assertSame(33.0,$enps);$this->assertTrue($responses->every(fn($row)=>$row->employee_id===null));}
public function test_recognition_requires_sender_identity_and_same_tenant():void{$sender=$this->employees[0];$recipient=$this->employees[1];$recognition=app(GiveRecognitionAction::class)->execute($sender,$recipient,'Müşteri sorununu sahiplenerek çözdü.','customer',true);$this->assertSame($recipient->id,$recognition->recipient_employee_id);$this->assertDatabaseHas('activity_logs',['action'=>'engagement_recognition_given']);}
private function activeSurvey(){ $this->actingAs($this->admin);$action=app(CreateSurveyAction::class);$survey=$action->execute(['title'=>'Haftalık Nabız','starts_on'=>today(),'ends_on'=>today()->addWeek(),'is_anonymous'=>true,'minimum_report_count'=>3,'questions'=>[['id'=>'enps','label'=>'Öneri','type'=>'enps'],['id'=>'energy','label'=>'Enerji','type'=>'scale']]]);return $action->transition($survey,'active');}}
